local function SortNumbers(left, right)
	return tonumber(left) < tonumber(right)
end

local function GetOrderableProfessionData(AF, professionID)
	local baseProfessionID = AF:GetSupportedProfessionID(professionID)
	if not baseProfessionID then
		return nil
	end
	local data = AF.ORDERABLE_RECIPES_BY_PROFESSION
	return type(data) == "table" and data[baseProfessionID] or nil
end

local function GetOrderableRecipeDataVersionText(version)
	local versions = {}
	if type(version) ~= "table" then
		local versionNumber = tonumber(version)
		if versionNumber then
			table.insert(versions, versionNumber)
		end
		table.sort(versions, SortNumbers)
		return #versions > 0 and table.concat(versions, ",") or "0"
	end

	for key, value in pairs(version) do
		local versionNumber = tonumber(value == true and key or value)
		if versionNumber then
			table.insert(versions, versionNumber)
		end
	end
	table.sort(versions, SortNumbers)
	return #versions > 0 and table.concat(versions, ",") or "0"
end

function AF:GetOrderableRecipeDataVersion()
	return GetOrderableRecipeDataVersionText(self.ORDERABLE_RECIPE_DATA_VERSION)
end

local function GetMergedOrderableRecipeDataVersionText(version, build)
	local versions = {}
	local seen = {}
	local function add(value)
		local versionNumber = tonumber(value)
		if versionNumber and not seen[versionNumber] then
			seen[versionNumber] = true
			table.insert(versions, versionNumber)
		end
	end

	if type(version) == "table" then
		for key, value in pairs(version) do
			add(value == true and key or value)
		end
	else
		add(version)
	end
	add(build)
	table.sort(versions, SortNumbers)
	return #versions > 0 and table.concat(versions, ",") or "0"
end

local function BuildOrderableRecipeDataSignature(data)
	if type(data) ~= "table" then
		return ""
	end

	local parts = {}
	local professions = {}
	for professionID in pairs(data) do
		table.insert(professions, tonumber(professionID) or professionID)
	end
	table.sort(professions, SortNumbers)
	for _, professionID in ipairs(professions) do
		local professionData = data[professionID] or data[tostring(professionID)]
		if type(professionData) == "table" then
			table.insert(parts, tostring(professionID))
			table.insert(parts, "{")
			local abilities = {}
			for skillLineAbilityID in pairs(professionData) do
				table.insert(abilities, tonumber(skillLineAbilityID) or skillLineAbilityID)
			end
			table.sort(abilities, SortNumbers)
			for _, skillLineAbilityID in ipairs(abilities) do
				table.insert(parts, tostring(skillLineAbilityID))
				table.insert(parts, "=")
				table.insert(parts, tostring(professionData[skillLineAbilityID] or professionData[tostring(skillLineAbilityID)] or ""))
				table.insert(parts, ",")
			end
			table.insert(parts, "}")
		end
	end
	return table.concat(parts)
end

local function CountTableEntries(data)
	local count = 0
	for _ in pairs(data or {}) do
		count = count + 1
	end
	return count
end

function AF:HasOrderableRecipeData(professionID)
	local professionData = GetOrderableProfessionData(self, professionID)
	return type(professionData) == "table" and next(professionData) ~= nil
end

function AF:IsRecipeOrderableForScan(profession, recipeInfo)
	if type(recipeInfo) ~= "table" then
		return true
	end
	local professionID = profession and profession.id or recipeInfo.professionID
	local professionData = GetOrderableProfessionData(self, professionID)
	if type(professionData) ~= "table" or next(professionData) == nil then
		return true
	end
	local skillLineAbilityID = tonumber(recipeInfo.skillLineAbilityID)
	if not skillLineAbilityID then
		return true
	end
	return professionData[skillLineAbilityID] ~= nil
end

local function GetCustomerOrderSearchParams()
	return {
		categoryFilters = {},
		searchText = nil,
		minLevel = 0,
		maxLevel = 9999,
		uncollectedOnly = false,
		usableOnly = false,
		upgradesOnly = false,
		currentExpansionOnly = false,
		includePoor = true,
		includeCommon = true,
		includeUncommon = true,
		includeRare = true,
		includeEpic = true,
		includeLegendary = true,
		includeArtifact = true,
		isFavoritesSearch = false,
	}
end

function AF:BuildOrderableRecipeDataDump()
	if not C_CraftingOrders or not C_CraftingOrders.GetCustomerOptions then
		return nil, "C_CraftingOrders.GetCustomerOptions unavailable"
	end

	local ok, results = pcall(C_CraftingOrders.GetCustomerOptions, GetCustomerOrderSearchParams())
	if not ok then
		return nil, tostring(results)
	end
	if type(results) ~= "table" or type(results.options) ~= "table" then
		return nil, "customer options unavailable; open the Crafting Order customer panel and try again"
	end

	local byProfession = {}
	local optionCount = 0
	local skippedCount = 0
	for _, option in ipairs(results.options) do
		local skillLineAbilityID = tonumber(option.skillLineAbilityID)
		local itemID = tonumber(option.itemID)
		local professionID = self:GetSupportedProfessionID(option.professionID)
		if skillLineAbilityID and professionID then
			optionCount = optionCount + 1
			byProfession[professionID] = byProfession[professionID] or {}
			byProfession[professionID][skillLineAbilityID] = itemID or true
		else
			skippedCount = skippedCount + 1
		end
	end

	local build = select(4, GetBuildInfo())
	local versionText = GetMergedOrderableRecipeDataVersionText(self.ORDERABLE_RECIPE_DATA_VERSION, build)
	local versionAssignment = "AF.ORDERABLE_RECIPE_DATA_VERSION={" .. versionText .. "}"
	local changed = BuildOrderableRecipeDataSignature(self.ORDERABLE_RECIPES_BY_PROFESSION) ~= BuildOrderableRecipeDataSignature(byProfession)
	if not changed then
		return versionAssignment, nil, {
			build = build,
			changed = false,
			options = optionCount,
			skipped = skippedCount,
			professions = CountTableEntries(byProfession),
		}
	end

	local parts = {
		versionAssignment,
		"AF.ORDERABLE_RECIPES_BY_PROFESSION={",
	}

	local professions = {}
	for professionID in pairs(byProfession) do
		table.insert(professions, professionID)
	end
	table.sort(professions, SortNumbers)
	for _, professionID in ipairs(professions) do
		table.insert(parts, string.format("[%d]={", professionID))
		local abilities = {}
		for skillLineAbilityID in pairs(byProfession[professionID]) do
			table.insert(abilities, skillLineAbilityID)
		end
		table.sort(abilities, SortNumbers)
		for _, skillLineAbilityID in ipairs(abilities) do
			table.insert(parts, string.format("[%d]=%s,", skillLineAbilityID, tostring(byProfession[professionID][skillLineAbilityID])))
		end
		table.insert(parts, "},")
	end
	table.insert(parts, "}")

	return table.concat(parts), nil, {
		build = build,
		changed = true,
		options = optionCount,
		skipped = skippedCount,
		professions = #professions,
	}
end

function AF:DumpOrderableRecipeData()
	local dump, err, stats = self:BuildOrderableRecipeDataDump()
	if not dump then
		self:Print("Orderable recipe dump failed: " .. tostring(err))
		return
	end

	self.lastOrderableRecipeDump = dump
	_G.ArtisanFinderOrderableRecipeDump = dump
	self.debugLogLines = self.debugLogLines or {}
	table.insert(self.debugLogLines, string.format(
		"[orderable-dump] changed=%s build=%s options=%d professions=%d %s",
		tostring(stats and stats.changed == true),
		tostring(stats and stats.build or ""),
		tonumber(stats and stats.options) or 0,
		tonumber(stats and stats.professions) or 0,
		dump
	))
	if self.debugLogFrame and self.debugLogFrame:IsShown() then
		self:RefreshDebugLogFrame()
	end
	if stats and stats.changed == false then
		self:Print(string.format(
			"Orderable recipe dump ready: no recipe changes, version line only, build %s. Copy ArtisanFinderOrderableRecipeDump or open /af debug logs.",
			tostring(stats.build or "")
		))
	else
		self:Print(string.format(
			"Orderable recipe dump ready: recipe changes found, %d options, %d professions, build %s. Copy ArtisanFinderOrderableRecipeDump or open /af debug logs.",
			tonumber(stats and stats.options) or 0,
			tonumber(stats and stats.professions) or 0,
			tostring(stats and stats.build or "")
		))
	end
end
